import anthropic, json

client = anthropic.Anthropic()

SHELL_TOOL_SCHEMA = {
    "name": "run_shell",
    "description": (
        "Execute a shell command on the local machine and return stdout, stderr, "
        "and the exit code. Use for: reading files, running scripts, querying system "
        "state, installing packages, running tests. "
        "Constraints: command must use an allowed binary; no shell operators (|, &&, ;, $()). "
        "For pipelines, write the equivalent Python and use run_python instead."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "command": {
                "type": "string",
                "description": "The command to run (e.g. 'ls -la /tmp'). Single binary only — no pipes or shell operators.",
            },
            "cwd": {
                "type": "string",
                "description": "Working directory for the command. Defaults to the project root.",
            },
        },
        "required": ["command"],
    },
}

def handle_tool_call(tool_name: str, tool_input: dict) -> str:
    if tool_name == "run_shell":
        try:
            result = run_shell(
                command=tool_input["command"],
                cwd=tool_input.get("cwd"),
            )
            return json.dumps(result)
        except ShellCommandError as e:
            return json.dumps({"error": str(e), "exit_code": -1})
    raise ValueError(f"Unknown tool: {tool_name}")

def run_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    while True:
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=1024,
            tools=[SHELL_TOOL_SCHEMA],
            messages=messages,
        )
        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if b.type == "text"), "")
        tool_results = [
            {
                "type": "tool_result",
                "tool_use_id": b.id,
                "content": handle_tool_call(b.name, b.input),
            }
            for b in response.content if b.type == "tool_use"
        ]
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

from pathlib import Path

PROJECT_ROOT = Path("/workspace/myproject").resolve()

def safe_cwd(requested: str | None) -> Path:
    """Resolve cwd to an absolute path that stays inside PROJECT_ROOT."""
    if requested is None:
        return PROJECT_ROOT
    resolved = (PROJECT_ROOT / requested).resolve()
    # Reject paths outside the project root
    try:
        resolved.relative_to(PROJECT_ROOT)
    except ValueError:
        raise ShellCommandError(
            f"Working directory '{requested}' is outside the project root."
        )
    if not resolved.is_dir():
        raise ShellCommandError(f"'{resolved}' is not a directory.")
    return resolved
